import { rowSelectLinkWithoutParents, rowSelectLinkWithParents, } from "@1771technologies/lytenyte-shared";
import { useEffect, useMemo, useRef } from "react";
import { cleanTree } from "./clean-tree.js";
import { useControlled } from "../../hooks/use-controlled.js";
import { useEvent } from "../../hooks/use-event.js";
import { equal } from "@1771technologies/js-utils";
export function useRowSelection(userSelection, onRowSelectionChange, isolatedSelection, rowSelectionKey, idUniverse, rootIds, rootCount, globalRefresh) {
    const [rowSelectionsRaw, setRowSelectionsRaw] = useControlled({
        controlled: userSelection,
        default: isolatedSelection
            ? { kind: "isolated", selected: false, exceptions: new Set() }
            : { kind: "linked", selected: false, children: new Map() },
    });
    const rowSelections = useMemo(() => {
        if (rowSelectionsRaw.kind === "isolated")
            return rowSelectionsRaw;
        return rowSelectLinkWithParents(rowSelectionsRaw);
    }, [rowSelectionsRaw]);
    const prevIsolated = useRef(isolatedSelection);
    const prevKey = useRef(rowSelectionKey);
    useEffect(() => {
        if (prevIsolated.current === isolatedSelection && equal(prevKey.current, rowSelectionKey))
            return;
        prevKey.current = rowSelectionKey;
        prevIsolated.current = isolatedSelection;
        setRowSelectionsRaw(isolatedSelection
            ? { kind: "isolated", selected: false, exceptions: new Set() }
            : { kind: "linked", selected: false, children: new Map() });
        globalRefresh(Date.now());
    }, [globalRefresh, isolatedSelection, rowSelectionKey, setRowSelectionsRaw]);
    const rowSelectionsSet = useEvent((s) => {
        const nextState = typeof s === "function" ? s(rowSelections) : s;
        if (nextState.kind === "linked")
            cleanTree(nextState, idUniverse, rootIds, rootCount);
        if (nextState.kind === "isolated" && idUniverse) {
            const next = nextState;
            next.exceptions = nextState.exceptions.intersection(idUniverse);
            if (next.exceptions.size >= idUniverse.size) {
                // flip whatever the selection is
                next.selected = !next.selected;
                next.exceptions = new Set();
            }
        }
        const without = nextState.kind === "isolated" ? nextState : rowSelectLinkWithoutParents(nextState);
        if (equal(without, rowSelectionsRaw))
            return;
        setRowSelectionsRaw(without);
        onRowSelectionChange?.(without);
    });
    useEffect(() => {
        if (!idUniverse)
            return;
        rowSelectionsSet((prev) => prev);
    }, [idUniverse, rowSelectionsSet]);
    const selectionRef = useRef({});
    Object.assign(selectionRef.current, {
        rowSelectionsRaw,
        rowSelections,
        rowSelectionsSet,
    });
    return selectionRef.current;
}
